@app.route("/sso", methods=["GET", "POST"])
def sso():
    sp_entity_id = _get_sp_entity_id_from_request()
    if not sp_entity_id:
        abort(400, "Missing sp (SP entityId) parameter")

    sp_conf = _load_sp_config(sp_entity_id)

    relay_state = request.values.get("RelayState", DEFAULT_RELAY_STATE)
    saml_request = request.values.get("SAMLRequest", "")

    if saml_request:
        settings = _build_saml_settings(sp_conf)
        auth = OneLogin_Saml2_Auth(_prepare_flask_request(request), settings)
        try:
            auth.process_request()
        except Exception:
            pass
        errors = []
        try:
            errors = auth.get_errors()
        except Exception:
            errors = []
        if errors:
            abort(400, "Invalid SAMLRequest: " + ", ".join(errors))

    return _render_login_form(sp_entity_id=sp_entity_id, relay_state=relay_state, saml_request=saml_request)


@app.post("/login")
def login():
    sp_entity_id = request.form.get("sp", "")
    if not sp_entity_id:
        abort(400, "Missing sp")
    sp_conf = _load_sp_config(sp_entity_id)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")
    relay_state = request.form.get("RelayState", DEFAULT_RELAY_STATE)
    saml_request = request.form.get("SAMLRequest", "")

    if not username or not password:
        abort(401, "Missing username/password")

    if password != os.environ.get("IDP_TEST_PASSWORD", "password"):
        abort(401, "Invalid credentials")

    in_response_to = "_" + str(uuid.uuid4())
    if saml_request:
        settings = _build_saml_settings(sp_conf)
        auth = OneLogin_Saml2_Auth(_prepare_flask_request(request), settings)
        try:
            auth.process_request()
            req_id = auth.get_last_request_id()
            if req_id:
                in_response_to = req_id
        except Exception:
            pass

    attrs = {
        "email": username,
        "uid": username.split("@")[0] if "@" in username else username,
        "displayName": username,
    }

    return _issue_saml_response(
        sp_conf=sp_conf,
        in_response_to=in_response_to,
        name_id=username,
        attributes=attrs,
        relay_state=relay_state,
    )


