def _ensure_dirs():
    os.makedirs(SP_METADATA_DIR, exist_ok=True)


def main():
    _ensure_dirs()
    if not os.path.exists(CERT_PATH) or not os.path.exists(KEY_PATH):
        print(f"Missing IdP signing cert/key at {CERT_PATH} and {KEY_PATH}", file=sys.stderr)
        sys.exit(2)
    if not os.path.exists(SSL_CERT) or not os.path.exists(SSL_KEY):
        print(f"Missing HTTPS cert/key at {SSL_CERT} and {SSL_KEY}", file=sys.stderr)
        sys.exit(2)

    app.run(
        host=APP_HOST,
        port=APP_PORT,
        ssl_context=(SSL_CERT, SSL_KEY),
        debug=False,
        threaded=True,
    )


if __name__ == "__main__":
    main()